import numpy as np

class ElasticNet:
    def __init__(self, alpha: float = 1.0, l1_ratio: float = 0.5):
        self.alpha = alpha
        self.l1_ratio = l1_ratio
        self.w = None
        self.b = 0.0

    @staticmethod
    def _soft_threshold(x, threshold):
        if x > threshold:
            return x - threshold
        elif x < -threshold:
            return x + threshold
        return 0.0

    def fit(self, X: np.ndarray, y: np.ndarray, epochs: int = 1000, tol: float = 1e-4) -> None:
        N, D = X.shape
        self.w = np.zeros(D)
        self.b = 0.0
        col_norms_sq = np.sum(X ** 2, axis=0)  # (D,)
        l1_term = self.alpha * self.l1_ratio * N
        l2_term = self.alpha * (1 - self.l1_ratio) * N

        for _ in range(epochs):
            w_old = self.w.copy()
            self.b = np.mean(y - X @ self.w)
            for j in range(D):
                r_j = y - self.b - X @ self.w + X[:, j] * self.w[j]
                rho_j = X[:, j] @ r_j
                denom = col_norms_sq[j] + l2_term
                if denom < 1e-10:
                    self.w[j] = 0.0
                else:
                    self.w[j] = self._soft_threshold(rho_j, l1_term) / denom
            if np.max(np.abs(self.w - w_old)) < tol:
                break

    def predict(self, X: np.ndarray) -> np.ndarray:
        return X @ self.w + self.b
